# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException

app = Flask(__name__)

ELASTICSEARCH_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
ELASTICSEARCH_TIMEOUT = float(os.getenv("ELASTICSEARCH_TIMEOUT", "2.0"))
ELASTICSEARCH_MAX_RETRIES = int(os.getenv("ELASTICSEARCH_MAX_RETRIES", "3"))
ELASTICSEARCH_RETRY_ON_TIMEOUT = os.getenv("ELASTICSEARCH_RETRY_ON_TIMEOUT", "true").lower() == "true"
SEARCH_RESULT_SIZE = int(os.getenv("SEARCH_RESULT_SIZE", "20"))
SEARCH_MAX_RESULT_WINDOW = int(os.getenv("SEARCH_MAX_RESULT_WINDOW", "100"))
SEARCH_MIN_QUERY_LENGTH = int(os.getenv("SEARCH_MIN_QUERY_LENGTH", "1"))

es = Elasticsearch(
    ELASTICSEARCH_URL,
    request_timeout=ELASTICSEARCH_TIMEOUT,
    max_retries=ELASTICSEARCH_MAX_RETRIES,
    retry_on_timeout=ELASTICSEARCH_RETRY_ON_TIMEOUT,
    http_compress=True,
)

def build_search_query(keyword: str, size: int):
    return {
        "size": size,
        "track_total_hits": False,
        "_source": ["id", "name", "description", "price", "currency", "category", "image_url", "in_stock"],
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": keyword,
                            "fields": [
                                "name^4",
                                "category^2",
                                "description"
                            ],
                            "type": "best_fields",
                            "operator": "and",
                            "fuzziness": "AUTO"
                        }
                    },
                    {
                        "match_phrase_prefix": {
                            "name": {
                                "query": keyword,
                                "boost": 5
                            }
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        }
    }

@app.get("/api/search")
def search_products():
    keyword = request.args.get("q", "", type=str).strip()
    size = request.args.get("size", SEARCH_RESULT_SIZE, type=int)

    if not keyword:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    if len(keyword) < SEARCH_MIN_QUERY_LENGTH:
        return jsonify({"error": f"Query parameter q must be at least {SEARCH_MIN_QUERY_LENGTH} character(s)"}), 400

    if size < 1:
        size = 1
    elif size > SEARCH_MAX_RESULT_WINDOW:
        size = SEARCH_MAX_RESULT_WINDOW

    try:
        response = es.search(
            index=ELASTICSEARCH_INDEX,
            body=build_search_query(keyword, size),
        )
        hits = response.get("hits", {}).get("hits", [])
        products = [
            {
                "score": hit.get("_score"),
                **hit.get("_source", {})
            }
            for hit in hits
        ]
        return jsonify({
            "query": keyword,
            "count": len(products),
            "products": products
        }), 200
    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))